import jwt from "jsonwebtoken";

// Signing/verifying session tokens for the bookmarks API.
//
// NOTE (fixture): this module is written against jsonwebtoken 8.x semantics.
// The tests in test/auth.test.js exercise the 8.x behaviour on purpose.
const SECRET = process.env.JWT_SECRET || "dev-only-fixture-secret";

// In 8.x, sign() accepts a payload that already carries its own `exp` claim
// as long as we do NOT also pass options.expiresIn. We build the expiry into
// the payload ourselves so callers can hand us fully-formed claim sets.
export function issueToken(claims, ttlSeconds = 3600) {
  const now = Math.floor(Date.now() / 1000);
  const payload = { ...claims, iat: now, exp: now + ttlSeconds };
  return jwt.sign(payload, SECRET, { algorithm: "HS256" });
}

export function verifyToken(token) {
  return jwt.verify(token, SECRET);
}

// 8.x returns the decoded payload (or null); we surface the raw header too.
export function inspect(token) {
  return jwt.decode(token, { complete: true });
}

import axios from "axios";

// Outbound URL preview: fetch a remote URL and report status + a snippet.
// Options come from the request query string (?timeout=..&maxRedirects=..).
export function parseFetchOptions(rawQuery) {
  const params = new URLSearchParams(rawQuery);
  const timeout = Number(params.get("timeout")) || 5000;
  const maxRedirects =
    params.get("maxRedirects") === null ? 5 : Number(params.get("maxRedirects"));
  return { timeout, maxRedirects };
}

export async function preview(url, rawQuery = "") {
  const { timeout, maxRedirects } = parseFetchOptions(rawQuery);
  const res = await axios.get(url, {
    timeout,
    maxRedirects,
    validateStatus: () => true,
  });
  const body = typeof res.data === "string" ? res.data : JSON.stringify(res.data);
  return {
    status: res.status,
    contentType: res.headers["content-type"] || null,
    snippet: body.slice(0, 200),
  };
}

import express from "express";
import { issueToken, verifyToken } from "./auth.js";
import { preview } from "./fetch.js";
import { importBookmarks } from "./importer.js";

// In-memory store — this is a fixture, not a real service.
const bookmarks = [];

export function createApp() {
  const app = express();
  app.use(express.json());
  app.use(express.text({ type: ["application/xml", "text/xml"] }));

  app.post("/login", (req, res) => {
    const { user } = req.body || {};
    if (!user) return res.status(400).json({ error: "user required" });
    const token = issueToken({ sub: user, role: "member" });
    res.json({ token });
  });

  app.get("/me", (req, res) => {
    const header = req.get("authorization") || "";
    const token = header.replace(/^Bearer\s+/i, "");
    try {
      const claims = verifyToken(token);
      res.json({ user: claims.sub, role: claims.role });
    } catch {
      res.status(401).json({ error: "invalid token" });
    }
  });

  app.get("/preview", async (req, res) => {
    const { url } = req.query;
    if (!url) return res.status(400).json({ error: "url required" });
    const rawQuery = req.originalUrl.split("?")[1] || "";
    try {
      const result = await preview(String(url), rawQuery);
      res.json(result);
    } catch (err) {
      res.status(502).json({ error: String(err.message || err) });
    }
  });

  app.post("/import", async (req, res) => {
    const xml = typeof req.body === "string" ? req.body : "";
    if (!xml) return res.status(400).json({ error: "xml body required" });
    try {
      const imported = await importBookmarks(xml);
      bookmarks.push(...imported);
      res.json({ imported: imported.length, total: bookmarks.length });
    } catch (err) {
      res.status(400).json({ error: String(err.message || err) });
    }
  });

  app.get("/bookmarks", (_req, res) => res.json({ bookmarks }));

  return app;
}

